import{_ as e,o,c as r,av as a}from"./chunks/framework.CaksihXG.js";const h=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"v2/guide/introduction.md","filePath":"v2/guide/introduction.md"}'),n={name:"v2/guide/introduction.md"};function i(d,t,s,l,u,c){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Vue DnD Kit v2 is a lightweight drag and drop library for Vue 3. It provides <strong>primitives</strong> (dragging, drop zones, constraints, selection) rather than ready-made UI components, so you can build any scenario with your own components.</p><h2 id="what-it-is" tabindex="-1">What it is <a class="header-anchor" href="#what-it-is" aria-label="Permalink to &quot;What it is&quot;">​</a></h2><p>The library is built around a <strong>provider</strong> (<code>DnDProvider</code>) and <strong>composables</strong>: <code>makeDraggable</code>, <code>makeDroppable</code>, <code>makeSelectionArea</code>, <code>makeConstraintArea</code>. No external dependencies — Vue only.</p><ul><li><strong>Draggable elements</strong> — any element can be made draggable.</li><li><strong>Drop zones</strong> — areas where draggable items can be dropped.</li><li><strong>Constraint areas</strong> — boundaries that keep dragged elements inside (e.g. a window or container).</li><li><strong>Selection areas</strong> — box selection to select multiple items (like in a file manager).</li></ul><p><strong>Keyboard</strong> (Enter/Space to start/drop, arrow keys to move, Escape to cancel) and <strong>touch devices</strong> are supported. The library is very light and does not pull in heavy dependencies.</p><h2 id="why-vue-dnd-kit" tabindex="-1">Why Vue DnD Kit <a class="header-anchor" href="#why-vue-dnd-kit" aria-label="Permalink to &quot;Why Vue DnD Kit&quot;">​</a></h2><p>There are very few flexible, high-quality drag and drop solutions for Vue. Most libraries are <strong>ready-made widgets</strong> (lists, kanban, sortable): fine for common cases, but with almost no customization. It’s hard to get your own layout, your own drop zones, and your own rules and animations.</p><p>Vue DnD Kit’s philosophy: you implement <strong>any</strong> scenario yourself by composing primitives. The library does not impose markup, styles, or components — only DnD logic. You build your components and wire them with <code>makeDraggable</code>, <code>makeDroppable</code>, etc. You get full control: any layout, any constraints, any animations and behavior.</p><h2 id="comparison-with-other-libraries" tabindex="-1">Comparison with other libraries <a class="header-anchor" href="#comparison-with-other-libraries" aria-label="Permalink to &quot;Comparison with other libraries&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Criteria</th><th>Vue DnD Kit v2</th><th>vue.draggable.next</th><th>vue-draggable-plus</th><th>vue3-dnd</th></tr></thead><tbody><tr><td><strong>Focus</strong></td><td>Universal primitives (drag, drop, selection, constraints)</td><td>List sorting (Sortable.js)</td><td>List sorting (Sortable.js)</td><td>Universal DnD (React DnD port)</td></tr><tr><td><strong>Dependencies</strong></td><td>Vue only</td><td>Vue + Sortable.js</td><td>Vue + Sortable.js</td><td>Vue + React DnD backends</td></tr><tr><td><strong>Customization</strong></td><td>Full: your components, zones, rules</td><td>Limited to Sortable options and CSS</td><td>More flexible via directives/selectors, still list-oriented</td><td>High, no built-in UI, via backends</td></tr><tr><td><strong>Drop zones</strong></td><td>✅ Built-in</td><td>⚠️ Via groups/lists</td><td>⚠️ Via groups/lists</td><td>✅ Via your markup</td></tr><tr><td><strong>Constraint area</strong></td><td>✅ Dedicated primitive</td><td>❌ Sortable options only</td><td>❌</td><td>✅ Implement manually</td></tr><tr><td><strong>Multi-selection</strong></td><td>✅ Dedicated primitive</td><td>❌</td><td>❌</td><td>Implement manually</td></tr><tr><td><strong>Keyboard</strong></td><td>✅ Built-in</td><td>❌</td><td>❌</td><td>Depends on backend</td></tr><tr><td><strong>Touch / mobile</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅ (touch-backend)</td></tr><tr><td><strong>TypeScript</strong></td><td>✅</td><td>Has types</td><td>✅</td><td>Depends on packages</td></tr></tbody></table><p><strong>In short:</strong></p><ul><li><strong>vue.draggable.next</strong> and <strong>vue-draggable-plus</strong> — good if you mainly need a <strong>sortable list</strong>; they’re simple and light. They’re not built for arbitrary drop zones, constraint boxes, or box selection.</li><li><strong>vue3-dnd</strong> — universal DnD inspired by React DnD, flexible but requires React DnD backends and more manual setup; no built-in primitives for selection or constraint areas.</li><li><strong>Vue DnD Kit v2</strong> — universal primitives for Vue 3 with no extra dependencies: drag, drop, selection area, and constraint area in one set, with keyboard and touch support, so you can build any case with your own components.</li></ul><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><ul><li><a href="/vue-dnd-kit/v2/guide/installation.html">Installation</a> — install the package.</li><li><a href="/vue-dnd-kit/v2/guide/quick-start.html">Quick Start</a> — your first draggable element and drop zone.</li><li><a href="/vue-dnd-kit/v2/guide/core/dnd-provider.html">DnDProvider</a>, <a href="/vue-dnd-kit/v2/guide/core/make-draggable.html">makeDraggable</a>, <a href="/vue-dnd-kit/v2/guide/core/make-droppable.html">makeDroppable</a>, <a href="/vue-dnd-kit/v2/guide/core/make-selection-area.html">makeSelectionArea</a>, <a href="/vue-dnd-kit/v2/guide/core/make-constraint-area.html">makeConstraintArea</a> — Core API reference.</li></ul>',15)])])}const p=e(n,[["render",i]]);export{h as __pageData,p as default};
